import React, { Fragment, useEffect, useState } from "react";
import AdminLayout from "../admin/layout";

import { getAllCategory } from "../admin/categories/FetchApi";
import { getAllProduct } from "../admin/products/FetchApi";
import { getAllOrder } from "../admin/orders/FetchApi";

const Panel = ({ title, children }) => (
  <div className="bg-white shadow p-4 rounded">
    <div className="font-semibold mb-2">{title}</div>
    {children}
  </div>
);

const SuperAdminDashboard = () => {

  const [categories, setCategories] = useState(0);
  const [organs, setOrgans] = useState(0);
  const [orders, setOrders] = useState(0);
  const [requests, setRequests] = useState(0);

  useEffect(() => {
    async function fetchData() {
      try {
        // const hospitalsData = await getAllHospital();


        // const patientsData = await getAllPatient();


        const categoriesData = await getAllCategory();
        setCategories(categoriesData.length);

        const organsData = await getAllProduct();
        setOrgans(organsData.length);

        const ordersData = await getAllOrder();
        setOrders(ordersData.length);
        setRequests(ordersData.length);
      } catch (error) {
        console.error("Error fetching data:", error);
      }
    }
    fetchData();
  }, []);

  const Details = (
    <div className="space-y-1 text-sm">
      {/* Superadmin details should be fetched dynamically */}
    </div>
  );

  const CategoriesPanel = (
    <div className="space-y-1 text-sm">
      <div>Heart</div>
    </div>
  );

  const OrgansPanel = (
    <div className="space-y-1 text-sm">
      <div>213123</div>
    </div>
  );



  const AnalyticsPanel = (
    <div className="grid grid-cols-2 gap-4 text-sm">

      <div>Categories: {categories}</div>
      <div>Organs: {organs}</div>
      <div>Orders: {orders}</div>
      <div>Requests: {requests}</div>
    </div>
  );

  return (
    <Fragment>
      <div className="p-4 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        <Panel title="Details">{Details}</Panel>

        <Panel title="Categories">{CategoriesPanel}</Panel>
        <Panel title="Organs">{OrgansPanel}</Panel>
        <Panel title="Analytics">{AnalyticsPanel}</Panel>
      </div>
    </Fragment>
  );
};

const SuperAdminPage = () => {
  return (
    <Fragment>
      <AdminLayout children={<SuperAdminDashboard />} />
    </Fragment>
  );
};

export default SuperAdminPage;
